package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private PrintStream originalOut;

    @BeforeEach
    void setUp() {
        originalOut = System.out;
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
    }

    @Test
    void testPrinterReturnsCSVPrinterWithSystemOut() throws IOException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
        // CSVPrinter.toString() is not guaranteed, so check class and out field via reflection
        assertEquals(CSVPrinter.class, printer.getClass());

        // Use reflection to check that the CSVPrinter's out is System.out
        try {
            java.lang.reflect.Field outField = CSVPrinter.class.getDeclaredField("out");
            outField.setAccessible(true);
            Object out = outField.get(printer);
            assertSame(System.out, out);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Reflection failed to access CSVPrinter.out field");
        }
    }
}
